SELECT [20061205-PrezziKidPerAnna-preFinal].No_ AS Article, [20061205-PrezziKidPerAnna-preFinal].[20061205-PrezziKidPerAnna-ListinoVendita].[Item].Description, [20061205-PrezziKidPerAnna-preFinal].[Variable Code Limit] AS Colors, [20061205-PrezziKidPerAnna-preFinal].[Line Code], [20061205-PrezziKidPerAnna-preFinal].[Season Code], [20061205-PrezziKidPerAnna-preFinal].[Product Family], [20061205-PrezziKidPerAnna-preFinal].[Product Sex], [20061205-PrezziKidPerAnna-preFinal].[Variable Code 01] AS Color, [20061205-PrezziKidPerAnna-preFinal].[20061205-PrezziKidPerAnna-ListinoVendita].[Variable Code].Description AS [Color Description], [20061205-PrezziKidPerAnna-preFinal].SizeRange, [20061205-PrezziKidPerAnna-preFinal].SalesPrice AS PreSalesPrice, [20061205-PrezziKidPerAnna-preFinal].RRP, IIf([Sales_Purchase Status Code]<>"",[Sales_Purchase Status Code] & "(ALL)",IIf([value]<>"",[value] & "(COL)","")) AS Status
FROM [20061205-PrezziKidPerAnna-preFinal]
ORDER BY [20061205-PrezziKidPerAnna-preFinal].[Variable Code Limit], [20061205-PrezziKidPerAnna-preFinal].[Variable Code 01], [20061205-PrezziKidPerAnna-preFinal].SizeRange;

